import React, { useState, useEffect, useRef } from "react";

// ─── REAL PHOTO DATA ───────────────────────────────────────────────────────────
const PETS = {
  dogs: [
    { name: "Affenpinscher", price: "₹10,000", badge: "POPULAR", desc: "Curious, lively & loyal", img: "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=400&q=80", color: "#FEF3C7" },
    { name: "Alaskan Husky", price: "₹20,000", badge: "NEW ARRIVAL", desc: "Energetic & friendly", img: "https://images.unsplash.com/photo-1605568427561-40dd23c2acea?w=400&q=80", color: "#D1FAE5" },
    { name: "Golden Retriever", price: "₹35,000", badge: null, desc: "Loyal family companion", img: "https://images.unsplash.com/photo-1633722715463-d30f4f325e24?w=400&q=80", color: "#FEF9C3" },
    { name: "Airedale Terrier", price: "₹4,00,000", badge: "PREMIUM", desc: "King of terriers", img: "https://images.unsplash.com/photo-1596492784531-6e6eb5ea9993?w=400&q=80", color: "#FCE7F3" },
    { name: "Labrador Retriever", price: "₹18,000", badge: "POPULAR", desc: "Playful & gentle", img: "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=400&q=80", color: "#DBEAFE" },
    { name: "German Shepherd", price: "₹25,000", badge: null, desc: "Brave & intelligent", img: "https://images.unsplash.com/photo-1589941013453-ec89f33b5e95?w=400&q=80", color: "#D1FAE5" },
    { name: "Beagle", price: "₹12,000", badge: "NEW ARRIVAL", desc: "Friendly & curious", img: "https://images.unsplash.com/photo-1505628346881-b72b27e84530?w=400&q=80", color: "#FEE2E2" },
    { name: "Shih Tzu", price: "₹22,000", badge: "PREMIUM", desc: "Elegant & affectionate", img: "https://images.unsplash.com/photo-1617895153857-82fe79b5a935?w=400&q=80", color: "#EDE9FE" },
  ],
  cats: [
    { name: "Persian Cat", price: "₹15,000", badge: "POPULAR", desc: "Elegant & affectionate", img: "https://images.unsplash.com/photo-1574158622682-e40e69881006?w=400&q=80", color: "#EDE9FE" },
    { name: "Maine Coon", price: "₹25,000", badge: "PREMIUM", desc: "Gentle giant of cats", img: "https://images.unsplash.com/photo-1615789591457-74a63395c990?w=400&q=80", color: "#DBEAFE" },
    { name: "Siamese", price: "₹12,000", badge: "NEW ARRIVAL", desc: "Vocal & social beauty", img: "https://images.unsplash.com/photo-1513360371669-4adf3dd7dff8?w=400&q=80", color: "#FEE2E2" },
    { name: "British Shorthair", price: "₹18,000", badge: null, desc: "Calm & independent", img: "https://images.unsplash.com/photo-1592194996308-7b43878e84a6?w=400&q=80", color: "#D1FAE5" },
    { name: "Scottish Fold", price: "₹30,000", badge: "PREMIUM", desc: "Adorably unique ears", img: "https://images.unsplash.com/photo-1567270671170-f48dd4d6c42f?w=400&q=80", color: "#FEF3C7" },
    { name: "Ragdoll", price: "₹28,000", badge: "POPULAR", desc: "Floppy & gentle", img: "https://images.unsplash.com/photo-1596854407944-bf87f6fdd49e?w=400&q=80", color: "#FCE7F3" },
    { name: "Bengal", price: "₹40,000", badge: "NEW ARRIVAL", desc: "Wild patterned beauty", img: "https://images.unsplash.com/photo-1586289883499-f11d28aaf52f?w=400&q=80", color: "#FEF9C3" },
    { name: "Abyssinian", price: "₹20,000", badge: null, desc: "Athletic & playful", img: "https://images.unsplash.com/photo-1548546738-8509cb246ed3?w=400&q=80", color: "#DBEAFE" },
  ],
  birds: [
    { name: "African Grey Parrot", price: "₹35,000", badge: "PREMIUM", desc: "Smartest talking bird", img: "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&q=80", color: "#FEF3C7" },
    { name: "Cockatiel", price: "₹5,000", badge: "POPULAR", desc: "Friendly & melodious", img: "https://images.unsplash.com/photo-1591198936750-16d8e15edb9e?w=400&q=80", color: "#D1FAE5" },
    { name: "Budgerigar", price: "₹2,500", badge: null, desc: "Colorful & cheerful", img: "https://images.unsplash.com/photo-1444464666168-49d633b86797?w=400&q=80", color: "#DBEAFE" },
    { name: "Lovebird", price: "₹8,000", badge: "NEW ARRIVAL", desc: "Sweet & affectionate", img: "https://images.unsplash.com/photo-1548767797-d8c844163c4a?w=400&q=80", color: "#FCE7F3" },
    { name: "Macaw", price: "₹1,20,000", badge: "PREMIUM", desc: "Majestic & colorful", img: "https://images.unsplash.com/photo-1552728089-57bdde30beb3?w=400&q=80", color: "#FEE2E2" },
    { name: "Conure", price: "₹15,000", badge: "POPULAR", desc: "Playful little parrot", img: "https://images.unsplash.com/photo-1557050543-4d5f4e07ef46?w=400&q=80", color: "#FEF9C3" },
    { name: "Finch", price: "₹1,500", badge: null, desc: "Tiny & tuneful", img: "https://images.unsplash.com/photo-1444464666168-49d633b86797?w=400&q=80", color: "#EDE9FE" },
    { name: "Cockatoo", price: "₹80,000", badge: "PREMIUM", desc: "Affectionate & loud", img: "https://images.unsplash.com/photo-1591198936750-16d8e15edb9e?w=400&q=80", color: "#D1FAE5" },
  ],
  fish: [
    { name: "Arowana", price: "₹50,000", badge: "PREMIUM", desc: "The lucky dragon fish", img: "https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=400&q=80", color: "#FEF3C7" },
    { name: "Betta Fish", price: "₹500", badge: "POPULAR", desc: "Stunning & easy care", img: "https://images.unsplash.com/photo-1520302630591-fd1c66edc19d?w=400&q=80", color: "#FEE2E2" },
    { name: "Koi Fish", price: "₹10,000", badge: null, desc: "Graceful pond beauty", img: "https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=400&q=80", color: "#D1FAE5" },
    { name: "Clownfish", price: "₹1,500", badge: "NEW ARRIVAL", desc: "Nemo's real cousin", img: "https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=400&q=80", color: "#DBEAFE" },
    { name: "Discus Fish", price: "₹8,000", badge: "PREMIUM", desc: "King of the aquarium", img: "https://images.unsplash.com/photo-1534043464124-3be32fe000c9?w=400&q=80", color: "#FCE7F3" },
    { name: "Goldfish", price: "₹200", badge: "POPULAR", desc: "Classic & cheerful", img: "https://images.unsplash.com/photo-1522069169874-c58ec4b76be5?w=400&q=80", color: "#FEF9C3" },
    { name: "Oscar Fish", price: "₹2,000", badge: null, desc: "Bold & intelligent", img: "https://images.unsplash.com/photo-1535591273668-578e31182c4f?w=400&q=80", color: "#EDE9FE" },
    { name: "Angel Fish", price: "₹3,000", badge: "NEW ARRIVAL", desc: "Elegant & graceful", img: "https://images.unsplash.com/photo-1520302630591-fd1c66edc19d?w=400&q=80", color: "#D1FAE5" },
  ],
};

// ─── PRODUCT CATEGORIES (Supertails style) ────────────────────────────────────
const PRODUCT_CATEGORIES = {
  dogs: [
    {
      section: "🍖 Food & Nutrition",
      items: [
