    { headline: "Professional", highlight: "Pet Care", sub: "Grooming, Vet Clinic, Training & 24/7 Emergency Services", img: "https://images.unsplash.com/photo-1574158622682-e40e69881006?w=700&q=80" },
    { headline: "Find Your", highlight: "Perfect Friend", sub: "Over 100+ breeds available — all certified & rehomeable", img: "https://images.unsplash.com/photo-1552728089-57bdde30beb3?w=700&q=80" },
  ];
  useEffect(() => {
    const t = setInterval(() => setSlide(s => (s + 1) % HERO_SLIDES.length), 4500);
