            <h1 style={{ fontSize: "clamp(2.5rem,5vw,4rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", lineHeight: 1.1, color: "#111827", margin: "0 0 1rem", letterSpacing: "-1px" }}>
              {current.headline}{" "}
              <span style={{ background: "linear-gradient(135deg,#F97316,#EF4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>{current.highlight}</span>
            </h1>
            <p style={{ fontSize: 18, color: "#6B7280", lineHeight: 1.7, marginBottom: "2rem", maxWidth: 480 }}>{current.sub}</p>
            <div style={{ display: "flex", gap: 14, flexWrap: "wrap" }}>
              <button onClick={() => setActivePage("dogs")} className="btn-scale" style={{ background: "linear-gradient(135deg,#F97316,#EF4444)", color: "#fff", padding: "14px 32px", borderRadius: 50, fontWeight: 800, fontSize: 16, border: "none", cursor: "pointer", boxShadow: "0 6px 20px rgba(249,115,22,0.4)", transition: "transform 0.2s" }}>
                Shop Now →
              </button>
              <button style={{ background: "#fff", color: "#374151", padding: "14px 32px", borderRadius: 50, fontWeight: 700, fontSize: 16, border: "2px solid #E5E7EB", cursor: "pointer", transition: "all 0.2s" }}>
