              </button>
            </div>
            <div style={{ display: "flex", gap: 32, marginTop: "2.5rem", paddingTop: "2rem", borderTop: "1px solid #E5E7EB" }}>
              {[["500+", "Happy Pets"], ["100+", "Breeds"], ["10K+", "Customers"], ["5★", "Rating"]].map(([num, label]) => (
                <div key={label} style={{ textAlign: "center" }}>
                  <div style={{ fontSize: 26, fontWeight: 900, color: "#F97316", fontFamily: "'Poppins',sans-serif" }}>{num}</div>
                  <div style={{ fontSize: 12, color: "#9CA3AF", marginTop: 2 }}>{label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: hero image + category cards */}
          <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
            <div className="img-zoom" style={{ borderRadius: 28, overflow: "hidden", boxShadow: "0 20px 60px rgba(0,0,0,0.15)", aspectRatio: "4/3", position: "relative" }}>
              <img src={current.img} alt="pets" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
              <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top,rgba(0,0,0,0.3),transparent)" }} />
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 10 }}>
              {NAV_CATEGORIES.map(cat => (
                <button key={cat.key} onClick={() => setActivePage(cat.key)} className="card-hover"
                  style={{ background: "#fff", borderRadius: 16, padding: "14px 8px", border: "1.5px solid #F3F4F6", cursor: "pointer", display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>
                  <span style={{ fontSize: 30 }}>{cat.emoji}</span>
                  <span style={{ fontSize: 12, fontWeight: 800, color: "#374151" }}>{cat.label}</span>
                </button>
              ))}
            </div>
            <div style={{ display: "flex", justifyContent: "center", gap: 8 }}>
              {HERO_SLIDES.map((_, i) => (
                <button key={i} onClick={() => setSlide(i)} style={{ width: i === slide ? 24 : 8, height: 8, borderRadius: 50, background: i === slide ? "#F97316" : "#D1D5DB", border: "none", cursor: "pointer", transition: "all 0.3s", padding: 0 }} />
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* CATEGORY QUICK ACCESS */}
      <section style={{ padding: "4rem 2rem", background: "#fff" }}>
        <div style={{ maxWidth: 1280, margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: "3rem" }}>
            <div style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 13, fontWeight: 700, color: "#F97316", textTransform: "uppercase", letterSpacing: "1.5px", marginBottom: 10 }}>🐾 Explore By Pet</div>
            <h2 style={{ fontSize: "clamp(1.8rem,3vw,2.5rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#111827", margin: "0 0 0.5rem", letterSpacing: "-0.5px" }}>Shop For Your Pet</h2>
            <p style={{ color: "#6B7280", fontSize: 16 }}>Find everything from pets to products — all in one place</p>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 20 }}>
            {NAV_CATEGORIES.map(cat => (
              <button key={cat.key} onClick={() => setActivePage(cat.key)} className="card-hover img-zoom"
                style={{ border: "none", cursor: "pointer", borderRadius: 24, overflow: "hidden", background: "none", padding: 0, textAlign: "left" }}>
                <div style={{ position: "relative", aspectRatio: "3/4" }}>
                  <img src={cat.hero} alt={cat.label} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                  <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to top,rgba(0,0,0,0.65) 40%,transparent)" }} />
                  <div style={{ position: "absolute", bottom: 20, left: 20, right: 20 }}>
                    <div style={{ fontSize: 36, marginBottom: 6 }}>{cat.emoji}</div>
                    <h3 style={{ color: "#fff", fontSize: 22, fontWeight: 900, fontFamily: "'Poppins',sans-serif", margin: "0 0 4px" }}>{cat.label}</h3>
                    <p style={{ color: "rgba(255,255,255,0.75)", fontSize: 13, margin: 0 }}>{cat.tagline}</p>
                  </div>
                </div>
              </button>
            ))}
          </div>
        </div>
      </section>

      {/* SERVICES */}
      <section style={{ background: "linear-gradient(135deg,#1A1A2E 0%,#2D1B69 100%)", padding: "5rem 2rem" }}>
