          <div style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 12, fontWeight: 700, color: "#FDBA74", textTransform: "uppercase", letterSpacing: "2px", marginBottom: 12 }}>⚡ What We Offer</div>
          <h2 style={{ fontSize: "clamp(1.8rem,3vw,2.5rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#fff", margin: "0 0 0.5rem" }}>Professional Pet Services</h2>
          <p style={{ color: "rgba(255,255,255,0.6)", fontSize: 16, maxWidth: 480, lineHeight: 1.7, margin: "0 0 3rem" }}>Everything your pet needs under one roof.</p>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(260px,1fr))", gap: 20 }}>
            {SERVICES.map(svc => (
              <div key={svc.title} className="card-hover"
                style={{ background: "rgba(255,255,255,0.07)", border: "1px solid rgba(255,255,255,0.12)", borderRadius: 20, padding: "28px 24px", cursor: "default" }}>
