                <h3 style={{ fontSize: 18, fontWeight: 800, color: "#fff", margin: "0 0 8px" }}>{svc.title}</h3>
                <p style={{ fontSize: 14, color: "rgba(255,255,255,0.6)", lineHeight: 1.6, margin: 0 }}>{svc.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA */}
      <section style={{ background: "linear-gradient(135deg,#F97316 0%,#EF4444 100%)", padding: "5rem 2rem", textAlign: "center" }}>
        <div style={{ maxWidth: 700, margin: "0 auto" }}>
          <div style={{ fontSize: 52, marginBottom: 16 }}>🐾</div>
          <h2 style={{ fontSize: "clamp(2rem,4vw,3rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#fff", margin: "0 0 1rem" }}>Ready to Bring Home a New Friend?</h2>
          <p style={{ fontSize: 18, color: "rgba(255,255,255,0.85)", margin: "0 auto 2rem", maxWidth: 500 }}>Thousands of happy pet parents trust Petology. Your perfect companion is waiting!</p>
          <button onClick={() => setActivePage("dogs")} className="btn-scale" style={{ background: "#fff", color: "#F97316", padding: "16px 44px", borderRadius: 50, fontWeight: 900, fontSize: 17, border: "none", cursor: "pointer", boxShadow: "0 8px 30px rgba(0,0,0,0.15)", transition: "transform 0.2s" }}>
