}

// ─── CATEGORY PAGE ─────────────────────────────────────────────────────────────
function CategoryPage({ cat, setActivePage }) {
  const [wishlist, setWishlist] = useState({});
  const [cartAdded, setCartAdded] = useState({});
  const [showAllPets, setShowAllPets] = useState(false);
  const [expandedSection, setExpandedSection] = useState(null);
  const [productCart, setProductCart] = useState({});

  const pets = PETS[cat.key];
  const products = PRODUCT_CATEGORIES[cat.key];
  const displayPets = showAllPets ? pets : pets.slice(0, 4);

  const toggleWish = (k) => setWishlist(w => ({ ...w, [k]: !w[k] }));
  const addCart = (k) => {
    setCartAdded(c => ({ ...c, [k]: true }));
    setTimeout(() => setCartAdded(c => ({ ...c, [k]: false })), 1600);
  };
  const addProductCart = (k) => {
    setProductCart(c => ({ ...c, [k]: true }));
    setTimeout(() => setProductCart(c => ({ ...c, [k]: false })), 1500);
  };

  return (
    <>
      {/* CATEGORY HERO */}
      <div style={{ position: "relative", height: 360, overflow: "hidden" }}>
        <img src={cat.hero} alt={cat.label} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
        <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to right,rgba(0,0,0,0.75) 40%,rgba(0,0,0,0.2))" }} />
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", padding: "0 3rem" }}>
          <div style={{ animation: "slideIn 0.5s ease" }}>
            <button onClick={() => setActivePage("home")} style={{ background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.3)", color: "#fff", padding: "6px 14px", borderRadius: 50, fontSize: 13, cursor: "pointer", marginBottom: 16, backdropFilter: "blur(8px)" }}>
              ← Home
            </button>
            <div style={{ fontSize: 52, marginBottom: 10 }}>{cat.emoji}</div>
            <h1 style={{ fontSize: "clamp(2.5rem,5vw,3.5rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#fff", margin: "0 0 10px", letterSpacing: "-1px" }}>{cat.label}</h1>
            <p style={{ color: "rgba(255,255,255,0.8)", fontSize: 18, margin: 0 }}>{cat.desc}</p>
          </div>
        </div>
        {/* Other cat quick links */}
        <div style={{ position: "absolute", top: 20, right: 24, display: "flex", gap: 8 }}>
          {NAV_CATEGORIES.filter(c => c.key !== cat.key).map(c => (
            <button key={c.key} onClick={() => setActivePage(c.key)}
              style={{ background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.3)", color: "#fff", padding: "7px 16px", borderRadius: 50, fontSize: 13, fontWeight: 700, cursor: "pointer", backdropFilter: "blur(8px)", display: "flex", alignItems: "center", gap: 5, transition: "all 0.2s" }}
              onMouseEnter={e => e.currentTarget.style.background = "rgba(249,115,22,0.85)"}
              onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.15)"}>
              {c.emoji} {c.label}
            </button>
          ))}
        </div>
      </div>

      {/* PET LISTINGS */}
      <section style={{ padding: "4rem 2rem", background: "#FAFAF8" }}>
        <div style={{ maxWidth: 1280, margin: "0 auto" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: "2.5rem" }}>
            <div>
              <div style={{ fontSize: 13, fontWeight: 700, color: "#F97316", textTransform: "uppercase", letterSpacing: "1.5px", marginBottom: 8 }}>🐾 Our Collection</div>
              <h2 style={{ fontSize: "clamp(1.8rem,3vw,2.5rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#111827", margin: 0 }}>Find Your Dream {cat.label.slice(0, -1)}</h2>
            </div>
            <div style={{ fontSize: 14, color: "#6B7280" }}>{pets.length} breeds available</div>
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(270px,1fr))", gap: 22 }}>
            {displayPets.map((pet, i) => {
              const key = `${cat.key}-${i}`;
              return (
                <div key={key} className="card-hover" style={{ background: "#fff", borderRadius: 24, overflow: "hidden", boxShadow: "0 2px 16px rgba(0,0,0,0.06)", border: "1px solid #F3F4F6", cursor: "pointer" }}>
                  <div className="img-zoom" style={{ height: 200, overflow: "hidden", position: "relative", background: pet.color }}>
                    <img src={pet.img} alt={pet.name} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                    {pet.badge && (
                      <span style={{ position: "absolute", top: 14, left: 14, background: BADGE_COLORS[pet.badge]?.bg, color: "#fff", fontSize: 10, fontWeight: 800, padding: "4px 10px", borderRadius: 50, letterSpacing: "0.8px" }}>{pet.badge}</span>
                    )}
                    <button onClick={(e) => { e.stopPropagation(); toggleWish(key); }}
                      style={{ position: "absolute", top: 12, right: 12, width: 36, height: 36, borderRadius: "50%", background: "#fff", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, boxShadow: "0 2px 8px rgba(0,0,0,0.12)" }}>
                      {wishlist[key] ? "❤️" : "🤍"}
                    </button>
                  </div>
                  <div style={{ padding: "16px 20px 20px" }}>
                    <div style={{ fontSize: 11, fontWeight: 700, color: "#9CA3AF", textTransform: "uppercase", letterSpacing: "1px", marginBottom: 4 }}>Pure Breed · {cat.label.slice(0, -1)}</div>
                    <h3 style={{ fontSize: 18, fontWeight: 800, color: "#111827", margin: "0 0 4px" }}>{pet.name}</h3>
                    <p style={{ fontSize: 13, color: "#9CA3AF", margin: "0 0 14px" }}>{pet.desc}</p>
                    <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 16 }}>
                      {["✅ Vaccinated", "📜 KCI Certified", "🏠 Rehomeable"].map(tag => (
                        <span key={tag} style={{ background: "#F3F4F6", color: "#6B7280", fontSize: 10, fontWeight: 600, padding: "3px 9px", borderRadius: 50 }}>{tag}</span>
                      ))}
                    </div>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                      <div>
                        <span style={{ fontSize: 22, fontWeight: 900, color: "#111827" }}>{pet.price}</span>
                        <span style={{ fontSize: 12, color: "#9CA3AF", marginLeft: 3 }}>onwards</span>
                      </div>
                      <button onClick={() => addCart(key)}
                        style={{ background: cartAdded[key] ? "#10B981" : "linear-gradient(135deg,#1A1A2E,#374151)", color: "#fff", border: "none", width: 42, height: 42, borderRadius: "50%", cursor: "pointer", fontSize: 18, display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.25s", boxShadow: "0 3px 10px rgba(0,0,0,0.2)" }}>
                        {cartAdded[key] ? "✓" : "🛒"}
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {!showAllPets && pets.length > 4 && (
            <div style={{ textAlign: "center", marginTop: "2.5rem" }}>
              <button onClick={() => setShowAllPets(true)} className="btn-scale"
                style={{ background: "linear-gradient(135deg,#F97316,#EF4444)", color: "#fff", border: "none", padding: "14px 40px", borderRadius: 50, fontWeight: 800, fontSize: 16, cursor: "pointer", boxShadow: "0 6px 20px rgba(249,115,22,0.35)", transition: "transform 0.2s" }}>
                View More {cat.label} ({pets.length - 4} more) →
              </button>
            </div>
          )}
        </div>
      </section>

      {/* PRODUCT CATEGORIES */}
      {products.map((section, si) => (
        <section key={si} style={{ padding: "3rem 2rem", background: si % 2 === 0 ? "#fff" : "#FAFAF8" }}>
          <div style={{ maxWidth: 1280, margin: "0 auto" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "2rem" }}>
              <div>
                <h2 style={{ fontSize: "clamp(1.4rem,2.5vw,1.9rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#111827", margin: 0 }}>{section.section}</h2>
                <p style={{ color: "#9CA3AF", fontSize: 14, margin: "4px 0 0" }}>Best products for your {cat.label.toLowerCase()}</p>
              </div>
              <button
                onClick={() => setExpandedSection(expandedSection === si ? null : si)}
                style={{ background: expandedSection === si ? "#F97316" : "transparent", color: expandedSection === si ? "#fff" : "#F97316", border: "2px solid #F97316", padding: "8px 20px", borderRadius: 50, fontWeight: 700, fontSize: 13, cursor: "pointer", transition: "all 0.2s" }}>
                {expandedSection === si ? "Show Less ↑" : "View More →"}
              </button>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(220px,1fr))", gap: 16 }}>
              {(expandedSection === si ? [...section.items, ...section.items.slice(0, 4)] : section.items).map((item, ii) => {
                const pkey = `${si}-${ii}`;
                return (
                  <div key={pkey} className="card-hover img-zoom" style={{ background: "#fff", borderRadius: 20, overflow: "hidden", boxShadow: "0 2px 12px rgba(0,0,0,0.06)", border: "1px solid #F3F4F6", cursor: "pointer" }}>
                    <div style={{ height: 150, overflow: "hidden", background: "#F9FAFB" }}>
                      <img src={item.img} alt={item.name} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
                    </div>
                    <div style={{ padding: "14px 16px 16px" }}>
                      <h4 style={{ fontSize: 14, fontWeight: 800, color: "#111827", margin: "0 0 4px" }}>{item.name}</h4>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 10 }}>
                        <span style={{ fontSize: 16, fontWeight: 900, color: "#F97316" }}>{item.price}</span>
                        <button onClick={() => addProductCart(pkey)}
                          style={{ background: productCart[pkey] ? "#10B981" : "#1A1A2E", color: "#fff", border: "none", padding: "7px 14px", borderRadius: 50, fontSize: 12, fontWeight: 700, cursor: "pointer", transition: "all 0.2s" }}>
                          {productCart[pkey] ? "✓ Added" : "+ Add"}
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </section>
      ))}

      {/* PROMO BANNER */}
      <section style={{ background: "linear-gradient(135deg,#F97316 0%,#EF4444 100%)", padding: "4rem 2rem", textAlign: "center" }}>
        <div style={{ maxWidth: 600, margin: "0 auto" }}>
          <h2 style={{ fontSize: "clamp(1.8rem,3vw,2.5rem)", fontWeight: 900, fontFamily: "'Poppins',sans-serif", color: "#fff", margin: "0 0 1rem" }}>
            Everything Your {cat.label.slice(0,-1)} Needs 🐾
          </h2>
          <p style={{ fontSize: 16, color: "rgba(255,255,255,0.85)", margin: "0 auto 2rem", maxWidth: 450 }}>
            From food to pharma, grooming to games — shop it all at Petology
          </p>
          <button onClick={() => setActivePage("home")} className="btn-scale"
            style={{ background: "#fff", color: "#F97316", padding: "14px 40px", borderRadius: 50, fontWeight: 900, fontSize: 16, border: "none", cursor: "pointer", boxShadow: "0 8px 30px rgba(0,0,0,0.15)", transition: "transform 0.2s" }}>
            ← Explore All Pets
          </button>
        </div>
      </section>
    </>
  );
}
